import{_ as a,c as t,o as n,ae as r}from"./chunks/framework.BvcDoAct.js";const M=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/Management2/PART2/5.md","filePath":"zh-cn/Management2/PART2/5.md"}'),o={name:"zh-cn/Management2/PART2/5.md"};function p(I,e,S,E,T,s){return n(),t("div",null,[...e[0]||(e[0]=[r('<p>► 2023/01</p><h2 id="现在打造第二个男团-mazzel-的理由" tabindex="-1">现在打造第二个男团“MAZZEL”的理由 <a class="header-anchor" href="#现在打造第二个男团-mazzel-的理由" aria-label="Permalink to &quot;现在打造第二个男团“MAZZEL”的理由&quot;">​</a></h2><p>#新项目 #Mx2 #MAZZEL #焦虑 #走出迷宫的出口 #幸福</p><h3 id="「我当时真的非常非常焦虑。事情就是这样——做了才会动-不做就不会动。不做就永远无法推进」" tabindex="-1">「我当时真的非常非常焦虑。事情就是这样——做了才会动，不做就不会动。不做就永远无法推进」 <a class="header-anchor" href="#「我当时真的非常非常焦虑。事情就是这样——做了才会动-不做就不会动。不做就永远无法推进」" aria-label="Permalink to &quot;「我当时真的非常非常焦虑。事情就是这样——做了才会动，不做就不会动。不做就永远无法推进」&quot;">​</a></h3><p><strong>由SKY-HI率领的BMSG推出的第二个唱跳组合“MAZZEL”，其诞生过程被记录在选秀纪录片《MISSIONx2》（以下简称“Mx2”）中，目前正在播出。</strong></p><p><strong>在诞生了BE:FIRST的选秀《THE FIRST》之后成为练习生的RAN与REIKO，在选秀结束后也展开了各种活动。RAN在2021年9月、10月以及2022年1月出演舞台剧《绝对青春合唱喜剧〈SING!!!〉》并担任主演；REIKO则在2021年10月参与了SKY-HI的《One More Day feat.REIKO》，并与SKY-HI一同登上《スッキリ》，之后还随SKY-HI参加了《SKY-HI HALL TOUR 2022 -八面六臂-》的9场巡演。2021年11月与12月，两人一起参加了时尚品牌TOMMY HILFIGER的访谈活动，2022年1月也登上了《THE FIRST》的收官演唱会“THE FIRST FINAL”。《Mx2》的第一集，则从这些活动告一段落的4月开始。</strong></p><p><strong>从时间线来看，可以再次感受到，《THE FIRST》之后不仅是BE:FIRST，就连第二个组合的推进节奏也相当之快。关于MAZZEL的出道，SKY-HI坦言：“我当时真的非常非常焦虑。”</strong></p><p>虽然说过很多次了，但REIKO本身既有作为SOLO艺人发展的可能，也有成为组合成员的可能，所以我无论如何都希望他能以我巡演开场嘉宾的身份一起参与，这点也拜托工作人员帮忙实现了。在推进这些个人活动的同时，其他时间也让他们一起训练，然后在4月正式启动了《Mx2》。</p><p>说真的，当时我非常非常焦虑。事情就是这样——做了才会动，不做就不会动。不做就不会推进。所以我也很想尽快把为第二个组合准备的人选聚齐。其实在2021年10月和REIKO、Aile The Shota一起上《スッキリ》的时候，我本来就想公布第二个组合的构想。但那时BE:FIRST刚刚顺利完成预出道，正处在即将正式出道的微妙时期，各方面都有反对意见，所以我只好作罢，但那种焦虑真的很强（笑）。</p><p>后来我又想，要不要在年初1月的“THE FIRST FINAL”上公布。但那时KAIRYU和SEITO已经以练习生身份加入了，我们也在不断调整方向……2022年我依然非常焦虑，但还是一边冷静观察局势，一边等项目阶段结束，最终在11月宣布，包括“已经成团”这一点也一并公开，并决定在第一集就让所有成员登场。</p><p><strong>像BMSG这样成立才3年、规模并不算大的公司，同时推进两个男团，其实并不容易。但即便如此，现在去做这件事的意义依然非常大。</strong></p><p>因为我真正想做的是改变既有的系统本身，所以“存在各种不同形态的组合”这一点非常重要。BE:FIRST和MAZZEL的创作方向，我们在公司内部也是以“必须完全不同”为前提来积极推进的。其实还有很多“这样的日本男团也很帅”的可能性，连BE:FIRST都还没完全做到。但同时也必须重视“调性统一”（tone &amp; manner）。现在的BE:FIRST不能去做像MAZZEL那样的东西。</p><p>不过目前也存在一个难点：有不少人是因为共鸣《THE FIRST》，或者看到BE:FIRST与我之间的关系而来报名的，但《Mx2》和MAZZEL会是完全不同的东西，所以这里会产生一定的落差。“什么是MAZZEL的风格”大家肯定也会很好奇，但如果现在就把它语言化，反而会固化成一种刻板印象，所以我觉得还是通过今后的MAZZEL来让大家自然理解会更好。</p><p>推动多个组合并行，还有一个目的——就是为未来的“BMSG FES”创造一个能够持续带来新鲜感的环境。去年那场FES中，我和Novel Core对现场的情感，以及从《THE FIRST》延续而来的15人的故事，其实已经告一段落了，必须进入下一个阶段。我想做的是：有一个很帅的组合，同时还有另一个很帅的组合，多个优秀的组合之间产生有机的交叠与联动……这是我非常想实现的。理想情况下，也希望能与其他事务所合作，但至少先要打造出一个仅靠自家也能实现这种状态的环境。</p>',14)])])}const A=a(o,[["render",p]]);export{M as __pageData,A as default};
